/* ─────────────────────────────────────────────
   Recents (localStorage)
   ───────────────────────────────────────────── */
const LS_RECENTS = 'aura_cmdk_recent';
const MAX_RECENTS = 5;

function loadRecents() {
  try {
    const raw = localStorage.getItem(LS_RECENTS);
    return raw ? JSON.parse(raw).slice(0, MAX_RECENTS) : [];
  } catch { return []; }
}

function saveRecent(item) {
  try {
    const entry = {
      id: item.id, label: item.label,
      category: item.category || item._category,
      path: item.path,
      action: item.action || undefined,
      description: item.description || undefined,
    };
    let arr = loadRecents();
    arr = [entry, ...arr.filter(r => r.id !== item.id)].slice(0, MAX_RECENTS);
    localStorage.setItem(LS_RECENTS, JSON.stringify(arr));
  } catch { /* ignore */ }
}

/* ─────────────────────────────────────────────
   Fuzzy matching (Levenshtein-like + substring + boundary)
   ───────────────────────────────────────────── */
function fuzzyScore(query, text) {
  if (!text) return { score: -1, indices: [] };
  const q = query.toLowerCase();
  const t = text.toLowerCase();

  // Exact substring match = highest priority
  if (t.includes(q)) {
    const start = t.indexOf(q);
    // Bonus for matching at start or word boundary
    const posBonus = start === 0 ? 50 : (t[start - 1] === ' ' || t[start - 1] === '/') ? 25 : 0;
    return { score: 1000 - start + posBonus, indices: Array.from({ length: q.length }, (_, i) => start + i) };
  }

  // Character-by-character fuzzy with Levenshtein-like tolerance
  let qi = 0, score = 0, lastIdx = -10;
  const indices = [];
  let skips = 0;

  for (let ti = 0; ti < t.length && qi < q.length; ti++) {
    if (t[ti] === q[qi]) {
      const consecutive = ti === lastIdx + 1 ? 10 : 0;
      const boundary = ti === 0 || t[ti - 1] === ' ' || t[ti - 1] === '/' || t[ti - 1] === '-' ? 12 : 0;
      // CamelCase boundary bonus
      const camel = ti > 0 && t[ti] !== t[ti].toUpperCase() && text[ti] === text[ti].toUpperCase() ? 8 : 0;
      score += 1 + consecutive + boundary + camel;
      lastIdx = ti;
      indices.push(ti);
      qi++;
    } else {
      skips++;
    }
  }

  if (qi < q.length) return { score: -1, indices: [] };
  // Penalize excessive skips (simulates edit distance tolerance)
  score -= Math.floor(skips / 3);
  return { score: Math.max(score, 1), indices };
}

/* ─────────────────────────────────────────────
   Highlighted text
   ───────────────────────────────────────────── */
function Hl({ text, indices, color }) {
  if (!indices || indices.length === 0) return <span>{text}</span>;
  const set = new Set(indices);
  return (
    <span>
      {text.split('').map((ch, i) =>
        set.has(i)
          ? <span key={i} style={{ color, fontWeight: 700 }}>{ch}</span>
          : <span key={i}>{ch}</span>
      )}
    </span>
  );
}

