/* ═════════════════════════════════════════════════════════════════════════════
   CommandPalette Component
   Props: open (boolean), onClose (function)
   ═════════════════════════════════════════════════════════════════════════════ */
export default function CommandPalette({ open, onClose }) {
  const nav = useNavigate();
  const themeCtx = useTheme();

  const [q, setQ] = useState('');
  const [activeIdx, setActiveIdx] = useState(0);
  const [strategies, setStrategies] = useState(null);
  const [symbols, setSymbols] = useState([]);
  const [symbolsLoading, setSymbolsLoading] = useState(false);
  const [executing, setExecuting] = useState(false);
  const inputRef = useRef(null);
  const listRef = useRef(null);
  const itemRefs = useRef({});
  const debounceRef = useRef(null);
  const abortRef = useRef(null);

  const isMac = typeof navigator !== 'undefined' && /Mac|iPod|iPhone|iPad/.test(navigator.platform);
  const shortcutLabel = isMac ? '\u2318K' : 'Ctrl+K';

  /* ── Fetch strategies once on first open ── */
  useEffect(() => {
    if (!open || strategies !== null) return;
    const ac = new AbortController();
    fetch(`${getApiBase()}/strategies`, { signal: ac.signal })
      .then(r => r.ok ? r.json() : [])
      .then(data => {
        const list = Array.isArray(data) ? data : (data?.strategies || []);
        setStrategies(list.map(s => ({
          id: `strat-${s.key || s.name}`,
          label: s.name || s.key || 'Unknown',
          subtitle: [
            s.direction,
            s.profit_factor != null || s.pf != null
              ? `PF ${Number(s.profit_factor ?? s.pf ?? 0).toFixed(2)}`
              : null,
            s.avg_score != null || s.score != null
              ? `Score ${Number(s.avg_score ?? s.score ?? 0).toFixed(1)}`
              : null,
          ].filter(Boolean).join(' \u2022 '),
          path: `/strategies/${encodeURIComponent(s.key || s.name)}`,
          category: 'Strategies',
          icon: ic.strategy,
          keywords: `${s.name || ''} ${s.key || ''} ${s.direction || ''} strategy`,
        })));
      })
      .catch(() => setStrategies([]));
    return () => ac.abort();
  }, [open, strategies]);

  /* ── Debounced symbol search (200ms) ── */
  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    if (abortRef.current) abortRef.current.abort();

    const query = q.trim();
    if (query.length < 1) {
      setSymbols([]);
      setSymbolsLoading(false);
      return;
    }

    setSymbolsLoading(true);
    debounceRef.current = setTimeout(() => {
      const ac = new AbortController();
      abortRef.current = ac;
      fetch(`${getApiBase()}/paper/symbols?q=${encodeURIComponent(query)}`, { signal: ac.signal })
        .then(r => r.ok ? r.json() : [])
        .then(data => {
          const list = Array.isArray(data) ? data : (data?.symbols || []);
          setSymbols(list.slice(0, 6).map(s => {
            const sym = typeof s === 'string' ? s : (s.symbol || s.ticker || String(s));
            const name = typeof s === 'object' ? (s.name || s.company || '') : '';
            return {
              id: `sym-${sym}`,
              label: sym,
              subtitle: name || undefined,
              path: `/charts?symbol=${encodeURIComponent(sym)}`,
              altPath: `/positions/${encodeURIComponent(sym)}`,
              category: 'Symbols',
              icon: ic.symbol,
              keywords: `${sym} ${name}`,
              isSymbol: true,
            };
          }));
          setSymbolsLoading(false);
        })
        .catch(err => {
          if (err.name !== 'AbortError') { setSymbols([]); setSymbolsLoading(false); }
        });
    }, 200);

    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
      if (abortRef.current) abortRef.current.abort();
    };
  }, [q]);

  /* ── Build scored results ── */
  const results = useMemo(() => {
    const query = q.trim();
    const strats = strategies || [];

    if (!query) {
      // No query: show recents first, then pages + commands
      const cmdMap = Object.fromEntries(COMMAND_ITEMS.map(a => [a.id, a]));
      const pageMap = Object.fromEntries(PAGE_COMMANDS.map(p => [p.id, p]));
      const recents = loadRecents().map(r => {
        const full = cmdMap[r.id] || pageMap[r.id] || {};
        return {
          ...full, ...r,
          _category: 'Recent', _indices: [], _score: 0,
          icon: full.icon || CATEGORY_ICON[r.category] || ic.recent,
        };
      });
      const pages = PAGE_COMMANDS.map(c => ({ ...c, category: 'Pages', _category: 'Pages', _indices: [], _score: 0 }));
      const commands = COMMAND_ITEMS.map(c => ({ ...c, category: 'Commands', _category: 'Commands', _indices: [], _score: 0 }));
      return [...recents, ...pages, ...commands];
    }

    // Score all sources: pages + commands + strategies
    const all = [
      ...PAGE_COMMANDS.map(c => ({ ...c, category: 'Pages' })),
      ...COMMAND_ITEMS.map(c => ({ ...c, category: 'Commands' })),
      ...strats,
    ];

    const scored = all.map(cmd => {
      const lr = fuzzyScore(query, cmd.label);
      const kr = fuzzyScore(query, cmd.keywords || '');
      const pr = cmd.path ? fuzzyScore(query, cmd.path) : { score: -1, indices: [] };
      const sr = cmd.subtitle ? fuzzyScore(query, cmd.subtitle) : { score: -1, indices: [] };
      const dr = cmd.description ? fuzzyScore(query, cmd.description) : { score: -1, indices: [] };
      const best = Math.max(lr.score, kr.score, pr.score, sr.score, dr.score);
      return {
        ...cmd,
        _category: cmd.category,
        _score: best,
        _indices: lr.score >= Math.max(kr.score, pr.score, sr.score, dr.score) ? lr.indices : [],
      };
    })
      .filter(c => c._score > 0)
      .sort((a, b) => b._score - a._score)
      .slice(0, 30);

    // Prepend live symbol results
    const symResults = symbols.map(s => ({
      ...s, _category: 'Symbols', _score: 500, _indices: [],
    }));

    return [...symResults, ...scored];
  }, [q, strategies, symbols]);

  /* ── Group items with category headers ── */
  const groupedItems = useMemo(() => {
    const items = [];
    const query = q.trim();

    if (!query) {
      for (const cat of ['Recent', 'Pages', 'Commands']) {
        const group = results.filter(r => r._category === cat);
        if (group.length === 0) continue;
        items.push({ type: 'header', category: cat, id: `h-${cat}` });
        for (const cmd of group) items.push({ type: 'command', ...cmd });
      }
    } else {
      // Group search results by category, preserving score order within groups
      const categoryOrder = ['Symbols', 'Strategies', 'Pages', 'Commands'];
      const grouped = {};
      for (const cmd of results) {
        const cat = cmd._category;
        if (!grouped[cat]) grouped[cat] = [];
        grouped[cat].push(cmd);
      }
      for (const cat of categoryOrder) {
        if (!grouped[cat] || grouped[cat].length === 0) continue;
        items.push({ type: 'header', category: cat, id: `h-${cat}` });
        for (const cmd of grouped[cat]) items.push({ type: 'command', ...cmd });
      }
      // Any remaining categories not in the order
      for (const cat of Object.keys(grouped)) {
        if (categoryOrder.includes(cat)) continue;
        items.push({ type: 'header', category: cat, id: `h-${cat}` });
        for (const cmd of grouped[cat]) items.push({ type: 'command', ...cmd });
      }
    }
    return items;
  }, [results, q]);

  /* ── Selectable items ── */
  const selectable = useMemo(() => groupedItems.filter(i => i.type === 'command'), [groupedItems]);
  const selectableMap = useMemo(() => {
    const m = new Map();
    selectable.forEach((item, idx) => m.set(item.id, idx));
    return m;
  }, [selectable]);

  /* ── Reset on query change ── */
  useEffect(() => { setActiveIdx(0); }, [q]);

  /* ── Scroll active into view ── */
  useEffect(() => {
    const active = selectable[activeIdx];
    if (active && itemRefs.current[active.id]) {
      itemRefs.current[active.id].scrollIntoView({ block: 'nearest', behavior: 'smooth' });
    }
  }, [activeIdx, selectable]);

  /* ── Execute command ── */
  const execute = useCallback(async (cmd) => {
    saveRecent(cmd);

    // If the command has an execute function, run it with feedback
    if (typeof cmd.execute === 'function') {
      setExecuting(true);
      try {
        await cmd.execute();
      } catch (err) {
        console.warn('[CommandPalette] Action failed:', err?.message);
      } finally {
        setExecuting(false);
        onClose();
        setQ('');
        setActiveIdx(0);
      }
      return;
    }

    // Close palette before navigation / legacy actions
    onClose();
    setQ('');
    setActiveIdx(0);

    // Navigation commands
    if (cmd.path) { nav(cmd.path); return; }

    // Legacy action string fallback
    switch (cmd.action) {
      case 'kill-switch':
        window.dispatchEvent(new CustomEvent('aura:open-kill-switch'));
        break;
      case 'toggle-dark':
        if (themeCtx) {
          const cur = themeCtx.theme;
          themeCtx.setTheme(cur === 'night' ? 'day' : 'night');
        }
        break;
      case 'toggle-theme':
        if (themeCtx) {
          const keys = themeCtx.themeKeys || ['night', 'day', 'midnight', 'ember'];
          const idx = keys.indexOf(themeCtx.theme);
          themeCtx.setTheme(keys[(idx + 1) % keys.length]);
        }
        break;
      case 'clear-cache':
        try {
          for (const k of Object.keys(localStorage)) {
            if (k.startsWith('aura_') || k.startsWith('cache_')) {
              localStorage.removeItem(k);
            }
          }
        } catch { /* ignore */ }
        break;
      case 'check-health':
        nav('/system-health');
        break;
      default:
        break;
    }
  }, [onClose, nav, themeCtx]);

  /* ── Keyboard navigation ── */
  const handleKeyDown = useCallback((e) => {
    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setActiveIdx(p => Math.min(p + 1, selectable.length - 1));
        break;
      case 'ArrowUp':
        e.preventDefault();
        setActiveIdx(p => Math.max(p - 1, 0));
        break;
      case 'Enter':
        e.preventDefault();
        if (selectable[activeIdx]) execute(selectable[activeIdx]);
        break;
      case 'Escape':
        e.preventDefault();
        onClose();
        setQ('');
        setActiveIdx(0);
        break;
      case 'Tab':
        e.preventDefault();
        if (e.shiftKey) setActiveIdx(p => Math.max(p - 1, 0));
        else setActiveIdx(p => Math.min(p + 1, selectable.length - 1));
        break;
      default:
        break;
    }
  }, [activeIdx, selectable, execute, onClose]);

  /* ── Focus / reset on open ── */
  useEffect(() => {
    if (open) {
      requestAnimationFrame(() => inputRef.current?.focus());
    } else {
      setQ('');
      setActiveIdx(0);
      setSymbols([]);
      setExecuting(false);
    }
  }, [open]);

  /* ═════════════════════════════════════════════
     Render — Radix Dialog for accessibility
     ═════════════════════════════════════════════ */
  return (
    <Dialog.Root open={open} onOpenChange={v => { if (!v) onClose(); }}>
      <AnimatePresence>
        {open && (
          <Dialog.Portal forceMount>
            {/* Overlay */}
            <Dialog.Overlay asChild>
              <motion.div
                key="cp-overlay"
                variants={overlayV}
                initial="hidden"
                animate="visible"
                exit="exit"
                transition={{ duration: 0.12 }}
                style={{
                  position: 'fixed', inset: 0, zIndex: 9999,
                  display: 'flex', alignItems: 'flex-start', justifyContent: 'center',
                  paddingTop: 'min(16vh, 120px)',
                  background: 'rgba(0,0,0,0.55)',
                  backdropFilter: 'blur(12px)', WebkitBackdropFilter: 'blur(12px)',
                }}
              />
            </Dialog.Overlay>

            {/* Content */}
            <Dialog.Content
              asChild
              onOpenAutoFocus={e => e.preventDefault()}
              aria-label="Command Palette"
            >
              <motion.div
                key="cp-modal"
                variants={modalV}
                initial="hidden"
                animate="visible"
                exit="exit"
                style={{
                  position: 'fixed',
                  top: 'min(16vh, 120px)',
                  left: '50%',
                  transform: 'translateX(-50%)',
                  zIndex: 10000,
                  width: '100%',
                  maxWidth: 600,
                  margin: '0 16px',
                  background: T.bgOverlay,
                  backdropFilter: 'blur(24px)',
                  WebkitBackdropFilter: 'blur(24px)',
                  border: `1px solid ${T.border}`,
                  borderRadius: 16,
                  boxShadow: `0 0 0 1px ${T.border}, 0 8px 40px rgba(0,0,0,0.5), 0 24px 80px rgba(0,0,0,0.4)`,
                  overflow: 'hidden',
                  display: 'flex',
                  flexDirection: 'column',
                  maxHeight: 'min(70vh, 560px)',
                  outline: 'none',
                }}
              >
                {/* Accessible title (visually hidden) */}
                <Dialog.Title className="sr-only" style={{
                  position: 'absolute', width: 1, height: 1,
                  overflow: 'hidden', clip: 'rect(0,0,0,0)', whiteSpace: 'nowrap',
                }}>
                  Command Palette
                </Dialog.Title>
                <Dialog.Description style={{
                  position: 'absolute', width: 1, height: 1,
                  overflow: 'hidden', clip: 'rect(0,0,0,0)', whiteSpace: 'nowrap',
                }}>
                  Search for pages, strategies, symbols, and commands. Arrow keys to navigate, Enter to select.
                </Dialog.Description>

                {/* ── Search Input ── */}
                <div style={{
                  display: 'flex', alignItems: 'center', gap: 12,
                  padding: '16px 18px', borderBottom: `1px solid ${T.border}`,
                }}>
                  <span style={{ color: T.textSec, flexShrink: 0, display: 'flex', opacity: 0.8 }}>
                    {ic.search}
                  </span>
                  <input
                    ref={inputRef}
                    type="text"
                    placeholder="Search pages, symbols, strategies, commands..."
                    value={q}
                    onChange={e => setQ(e.target.value)}
                    onKeyDown={handleKeyDown}
                    autoComplete="off"
                    spellCheck={false}
                    style={{
                      flex: 1, background: 'transparent', border: 'none', outline: 'none',
                      fontSize: 15, fontFamily: T.fontUI,
                      color: T.text, caretColor: T.blue,
                      letterSpacing: '0.01em',
                    }}
                  />
                  <kbd style={{
                    flexShrink: 0, padding: '3px 8px', fontSize: 11,
                    fontFamily: T.fontMono,
                    color: T.textSec, background: T.surface2,
                    border: `1px solid ${T.border}`, borderRadius: 6, lineHeight: '16px',
                  }}>
                    {shortcutLabel}
                  </kbd>
                </div>

                {/* ── Results ── */}
                <div ref={listRef} role="listbox" style={{
                  flex: 1, overflowY: 'auto', overflowX: 'hidden', padding: '6px 0',
                  position: 'relative',
                  /* Custom scrollbar */
                  scrollbarWidth: 'thin',
                  scrollbarColor: `${T.border} transparent`,
                }}>
                  {/* Spinner for symbol API */}
                  {symbolsLoading && q.trim().length > 0 && (
                    <div style={{
                      padding: '6px 18px', fontSize: 12, color: T.textSec, opacity: 0.6,
                      display: 'flex', alignItems: 'center', gap: 8,
                    }}>
                      <span style={{
                        display: 'inline-block', width: 12, height: 12,
                        border: `2px solid ${T.border}`, borderTopColor: T.blue,
                        borderRadius: '50%',
                        animation: 'cpSpin 0.4s linear infinite',
                      }} />
                      Searching symbols...
                      <style>{`@keyframes cpSpin { to { transform: rotate(360deg); } }`}</style>
                    </div>
                  )}

                  {/* Empty state */}
                  {groupedItems.length === 0 && !symbolsLoading && (
                    <div style={{
                      padding: '40px 18px', textAlign: 'center',
                      color: T.textSec, fontSize: 14,
                    }}>
                      <div style={{ fontSize: 32, marginBottom: 10, opacity: 0.25 }}>
                        {ic.search}
                      </div>
                      <div style={{ fontWeight: 500 }}>No matching results</div>
                      <div style={{ fontSize: 13, marginTop: 6, opacity: 0.5 }}>
                        Try a different search term or browse categories
                      </div>
                    </div>
                  )}

                  {/* Executing overlay */}
                  {executing && (
                    <div style={{
                      position: 'absolute', inset: 0, zIndex: 10,
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      background: `${T.bg}E8`, borderRadius: 16,
                    }}>
                      <div style={{
                        display: 'flex', alignItems: 'center', gap: 12,
                        color: T.blue, fontSize: 14, fontWeight: 600,
                      }}>
                        <span style={{
                          display: 'inline-block', width: 18, height: 18,
                          border: `2px solid ${T.border}`, borderTopColor: T.blue,
                          borderRadius: '50%',
                          animation: 'cpSpin 0.4s linear infinite',
                        }} />
                        Executing...
                      </div>
                    </div>
                  )}

                  {groupedItems.map((item, i) => {
                    if (item.type === 'header') {
                      const catColor = CATEGORY_COLOR[item.category] || T.textSec;
                      return (
                        <div key={item.id} style={{
                          display: 'flex', alignItems: 'center', gap: 8,
                          padding: '12px 18px 5px',
                          fontSize: 11, fontWeight: 700, textTransform: 'uppercase',
                          letterSpacing: '0.08em', color: catColor, opacity: 0.65,
                          userSelect: 'none',
                        }}>
                          <span style={{ display: 'flex', opacity: 0.7 }}>
                            {CATEGORY_ICON[item.category] || ic.page}
                          </span>
                          {CATEGORY_LABEL[item.category] || item.category}
                        </div>
                      );
                    }

                    // Command row
                    const sIdx = selectableMap.get(item.id) ?? -1;
                    const isActive = sIdx === activeIdx;
                    const isCmd = item._category === 'Commands' || (item.action && !item.path);
                    const isSym = item._category === 'Symbols' || item.isSymbol;
                    const accentColor = isCmd && item.color ? item.color : null;
                    const catColor = CATEGORY_COLOR[item._category] || T.blue;

                    return (
                      <motion.div
                        key={item.id}
                        ref={el => { itemRefs.current[item.id] = el; }}
                        custom={i}
                        variants={itemV}
                        initial="hidden"
                        animate="visible"
                        role="option"
                        aria-selected={isActive}
                        onClick={() => execute(item)}
                        onMouseEnter={() => setActiveIdx(sIdx)}
                        style={{
                          display: 'flex', alignItems: 'center', gap: 12,
                          padding: '9px 18px', margin: '1px 6px',
                          borderRadius: 10, cursor: 'pointer',
                          transition: 'background 0.12s, border-color 0.12s',
                          background: isActive
                            ? (accentColor ? `${accentColor}14` : `${catColor}12`)
                            : 'transparent',
                          borderLeft: isCmd && accentColor
                            ? `2px solid ${isActive ? accentColor : `${accentColor}50`}`
                            : isActive ? `2px solid ${catColor}` : '2px solid transparent',
                        }}
                      >
                        {/* Icon */}
                        <span style={{
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          width: 32, height: 32, borderRadius: 9, flexShrink: 0,
                          background: isActive
                            ? (accentColor ? `${accentColor}20` : `${catColor}18`)
                            : T.surface2,
                          color: isSym ? T.green
                            : item._category === 'Strategies' ? T.purple
                            : isCmd && accentColor ? accentColor
                            : item._category === 'Commands' ? T.amber
                            : isActive ? catColor : T.textSec,
                          transition: 'all 0.12s',
                        }}>
                          {item.icon || (isCmd ? ic.action : ic.page)}
                        </span>

                        {/* Label + subtitle/description */}
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{
                            fontSize: 14, fontWeight: 500, color: T.text,
                            lineHeight: '20px', whiteSpace: 'nowrap',
                            overflow: 'hidden', textOverflow: 'ellipsis',
                            fontFamily: isSym ? T.fontMono : T.fontUI,
                            letterSpacing: isSym ? '0.04em' : '0.005em',
                          }}>
                            <Hl text={item.label} indices={item._indices} color={accentColor || catColor} />
                          </div>
                          {/* Description for command items */}
                          {item.description && (
                            <div style={{
                              fontSize: 12, color: T.textSec,
                              opacity: isActive ? 0.85 : 0.5,
                              lineHeight: '16px', whiteSpace: 'nowrap',
                              overflow: 'hidden', textOverflow: 'ellipsis',
                            }}>
                              {item.description}
                            </div>
                          )}
                          {/* Strategy subtitle */}
                          {!item.description && item.subtitle && (
                            <div style={{
                              fontSize: 12, color: T.textSec,
                              opacity: isActive ? 0.85 : 0.5,
                              lineHeight: '16px', whiteSpace: 'nowrap',
                              overflow: 'hidden', textOverflow: 'ellipsis',
                              fontFamily: isSym ? T.fontMono : T.fontUI,
                            }}>
                              {item.subtitle}
                            </div>
                          )}
                          {/* Page path for pages without subtitle/description */}
                          {!item.description && !item.subtitle && item.path && (
                            <div style={{
                              fontSize: 12, color: T.textSec,
                              opacity: isActive ? 0.75 : 0.4,
                              fontFamily: T.fontMono,
                              lineHeight: '16px',
                            }}>
                              {item.path}
                            </div>
                          )}
                        </div>

                        {/* Keyboard shortcut hint for pages */}
                        {item.shortcut && !q.trim() && (
                          <span style={{
                            flexShrink: 0, display: 'flex', gap: 3,
                          }}>
                            {item.shortcut.split(' ').map((k, ki) => (
                              <kbd key={ki} style={{
                                fontSize: 10, fontFamily: T.fontMono,
                                padding: '2px 6px', borderRadius: 5,
                                background: T.surface2, color: T.textSec,
                                border: `1px solid ${T.border}`,
                                lineHeight: '14px', fontWeight: 500,
                              }}>
                                {k}
                              </kbd>
                            ))}
                          </span>
                        )}

                        {/* Category badge (search mode only) */}
                        {q.trim() && (
                          <span style={{
                            flexShrink: 0, fontSize: 10, fontWeight: 600,
                            padding: '2px 8px', borderRadius: 6,
                            background: `${catColor}14`,
                            color: catColor,
                            textTransform: 'uppercase', letterSpacing: '0.04em',
                          }}>
                            {CATEGORY_BADGE[item._category] || item._category}
                          </span>
                        )}

                        {/* Enter hint on active row */}
                        {isActive && (
                          <kbd style={{
                            flexShrink: 0, fontSize: 10,
                            fontFamily: T.fontMono,
                            padding: '2px 6px', borderRadius: 5,
                            background: T.surface2, color: T.textSec,
                            border: `1px solid ${T.border}`,
                          }}>
                            {'\u23CE'}
                          </kbd>
                        )}
                      </motion.div>
                    );
                  })}
                </div>

                {/* ── Footer ── */}
                <div style={{
                  display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                  padding: '9px 18px', borderTop: `1px solid ${T.border}`,
                  fontSize: 11, color: T.textSec, opacity: 0.55, userSelect: 'none',
                  background: `${T.bg}80`,
                }}>
                  <div style={{ display: 'flex', gap: 14 }}>
                    <span>{kbdMini('\u2191')}{kbdMini('\u2193')} navigate</span>
                    <span>{kbdMini('\u23CE')} select</span>
                    <span>{kbdMini('esc')} close</span>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
                    <span
                      style={{ cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4, opacity: 0.9 }}
                      onClick={() => { onClose(); window.dispatchEvent(new Event('aura:open-shortcuts')); }}
                      title="Keyboard shortcuts"
                    >
                      {kbdMini('?')} shortcuts
                    </span>
                    <span>{selectable.length} result{selectable.length !== 1 ? 's' : ''}</span>
                  </div>
                </div>
              </motion.div>
            </Dialog.Content>
          </Dialog.Portal>
        )}
      </AnimatePresence>
    </Dialog.Root>
  );
}

// Named export for backward compatibility
export { CommandPalette };
